/// Validates that a filename contains no path traversal or shell metacharacters.
fn validate_filename(filename: &str) -> Result<&str, ConversionError> {
    // Reject empty filenames
    if filename.is_empty() {
        return Err(ConversionError::InvalidFilename(
            "Filename cannot be empty".to_string(),
        ));
    }

    // Reject path traversal attempts
    if filename.contains("..") || filename.contains('/') || filename.contains('\\') {
        return Err(ConversionError::InvalidFilename(format!(
            "Filename contains path traversal characters: {}",
            filename
        )));
    }

    // Reject null bytes
    if filename.contains('\0') {
        return Err(ConversionError::InvalidFilename(
            "Filename contains null bytes".to_string(),
        ));
    }

    // Reject shell metacharacters as an extra safety measure
    const DANGEROUS_CHARS: &[char] = &[
        '|', '&', ';', '$', '`', '(', ')', '{', '}', '[', ']', '!', '#', '~', '<', '>', '\'',
        '"', '\n', '\r',
    ];

    for ch in DANGEROUS_CHARS {
        if filename.contains(*ch) {
            return Err(ConversionError::InvalidFilename(format!(
                "Filename contains disallowed character '{}': {}",
                ch, filename
            )));
        }
    }

    // Ensure the filename has only printable ASCII and common unicode
    for ch in filename.chars() {
        if ch.is_control() {
            return Err(ConversionError::InvalidFilename(format!(
                "Filename contains control characters: {}",
                filename
            )));
        }
    }

    Ok(filename)
}

